import { useNavigate } from 'react-router-dom';
import styled from 'styled-components';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import Container from '@mui/material/Container';
import Grid from '@mui/material/Grid';

import movie from '../Assets/movie.png'
import workout from '../Assets/workout.png'
import commandLine from '../Assets/commandLine.png'

const BoxWithHover = styled(Box)`
  transition: .5s;
  &:hover {
    transform: scale(1.05); /* Enlarge the image on hover */
  }
`;

const projectItem = (image, name, func) => {
  return (
    <Container>
        <Box 
          component='img'
          src={image}
          alt='logo'
        />
          <Typography>{name}</Typography>
    </Container>
  );
};

function Projects () {
    const navigate = useNavigate();
    const reroute = (path) => {
        return () => navigate(path);
        // return () => window.open(path, '_blank');
    };

    return (
        <Container
        >
            <Typography 
              id='projects'
              variant='h2' 
          sx={{
            display: 'flex', 
            flexDirection: 'column', 
            alignItems: 'center',
          }}        
            >
              Projects
            </Typography>

            <Box sx={{display: 'flex', flexDirection: 'row'}}>
            <Grid container direction='row' spacing={4} rows={1}> 
              <Grid item>
                {projectItem(movie, 'Topher Emby', reroute('/TopherEmby') )}
              </Grid>
              <Grid item>
                {projectItem(movie, 'Topher Emby', reroute('/TopherEmby') )}
              </Grid>
              <Grid item>
                {projectItem(movie, 'Topher Emby', reroute('/TopherEmby') )}
              </Grid>
              <Grid item>
                {projectItem(movie, 'Topher Emby', reroute('/TopherEmby') )}
              </Grid>
              <Grid item>
                {projectItem(movie, 'Topher Emby', reroute('/TopherEmby') )}
              </Grid>
            </Grid>
            </Box>

        </Container>
    );
}

export default Projects;
